import { NextRequest, NextResponse } from 'next/server';
import { decryptGHLSession, validateSessionData } from '@/lib/ghl/session-decrypt';
import { createAdminClient } from '@/lib/supabase/admin';

/**
 * Decrypt GHL SSO data from postMessage and create/update user session
 * This endpoint handles the encrypted user data received via postMessage
 */
export async function POST(request: NextRequest) {
  try {
    const { encryptedData } = await request.json();

    console.log('[SSO] Received decrypt request');

    if (!encryptedData) {
      console.error('[SSO] Missing encrypted data in request');
      return NextResponse.json(
        { error: 'Missing encrypted data' },
        { status: 400 }
      );
    }

    // Get shared secret from environment
    const sharedSecret = process.env.GHL_SHARED_SECRET;
    
    if (!sharedSecret) {
      console.error('[SSO] GHL_SHARED_SECRET not found in environment variables');
      return NextResponse.json(
        { 
          error: 'Server configuration error',
          details: 'GHL_SHARED_SECRET is not configured',
          help: 'Please add GHL_SHARED_SECRET to your Vercel environment variables. Get this from GHL App Settings > Advanced > Auth > Shared Secret'
        },
        { status: 500 }
      );
    }

    console.log('[SSO] Shared secret found, attempting decryption...');

    // Decrypt session data
    let sessionData;
    try {
      sessionData = decryptGHLSession(encryptedData, sharedSecret);
      console.log('[SSO] Decryption successful:', {
        userId: sessionData.userId,
        locationId: sessionData.locationId,
        companyId: sessionData.companyId
      });
    } catch (error) {
      console.error('[SSO] Decryption failed:', error);
      return NextResponse.json(
        { 
          error: 'Failed to decrypt SSO data',
          details: error instanceof Error ? error.message : 'Unknown error',
          help: 'Verify that GHL_SHARED_SECRET matches the one in your GHL app settings'
        },
        { status: 401 }
      );
    }

    // Validate session data
    if (!validateSessionData(sessionData)) {
      console.error('[SSO] Invalid session data - missing required fields');
      return NextResponse.json(
        { error: 'Invalid session data - missing required fields' },
        { status: 400 }
      );
    }

    console.log('[SSO] Session data validated, checking installation...');

    // Create Supabase admin client
    const supabase = createAdminClient();

    // Check if installation exists for this location
    const { data: installation, error: installError } = await supabase
      .from('installations')
      .select('*')
      .eq('location_id', sessionData.locationId)
      .single();

    if (installError) {
      console.error('[SSO] Error checking installation:', installError);
    }

    if (!installation) {
      console.warn('[SSO] No installation found for location:', sessionData.locationId);
      return NextResponse.json(
        { 
          error: 'App not installed',
          locationId: sessionData.locationId,
          message: 'Please install the app first from the GHL marketplace or via the OAuth flow'
        },
        { status: 403 }
      );
    }

    if (installation.status !== 'active') {
      console.warn('[SSO] Installation not active:', installation.status);
      return NextResponse.json(
        { 
          error: 'Installation inactive',
          status: installation.status,
          message: 'This app installation is not active. Please reinstall the app.'
        },
        { status: 403 }
      );
    }

    console.log('[SSO] Installation verified, creating user session...');

    // Create or get user in Supabase Auth
    const userEmail = sessionData.email || `${sessionData.userId}@ghl.internal`;
    
    const { data: authData, error: authError } = await supabase.auth.admin.createUser({
      email: userEmail,
      email_confirm: true,
      user_metadata: {
        ghl_user_id: sessionData.userId,
        location_id: sessionData.locationId,
        company_id: sessionData.companyId,
        name: sessionData.name,
        role: sessionData.role,
      },
    });

    if (authError && !authError.message.includes('already registered')) {
      console.error('[SSO] Supabase auth error:', authError);
      return NextResponse.json(
        { error: 'Failed to create user session' },
        { status: 500 }
      );
    }

    // Get or create user record
    const userId = authData?.user?.id;
    if (userId) {
      await supabase
        .from('users')
        .upsert({
          auth_id: userId,
          ghl_user_id: sessionData.userId,
          location_id: sessionData.locationId,
          company_id: sessionData.companyId,
          email: userEmail,
        }, {
          onConflict: 'ghl_user_id'
        });
    }

    // Generate session token
    const { data: sessionTokenData, error: sessionError } = await supabase.auth.admin.generateLink({
      type: 'magiclink',
      email: userEmail,
    });

    if (sessionError) {
      console.error('[SSO] Session generation error:', sessionError);
      return NextResponse.json(
        { error: 'Failed to generate session' },
        { status: 500 }
      );
    }

    console.log('[SSO] Authentication successful for location:', sessionData.locationId);

    return NextResponse.json({
      success: true,
      locationId: sessionData.locationId,
      companyId: sessionData.companyId,
      userId: sessionData.userId,
      session: sessionTokenData,
    });

  } catch (error) {
    console.error('[SSO] Unexpected error:', error);
    
    return NextResponse.json(
      { 
        error: 'Internal server error',
        details: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    );
  }
}